import requests
import json
import sys
from typing import List, Dict, Optional
from dataclasses import dataclass
from requests.auth import HTTPBasicAuth


@dataclass
class VHostConfig:
    name: str
    description: str = ""
    tracing: bool = False


@dataclass
class UserConfig:
    username: str
    password: str
    tags: str = ""


@dataclass
class PermissionConfig:
    vhost: str
    username: str
    configure: str = ".*"
    write: str = ".*"
    read: str = ".*"


class RabbitMQManager:
    def __init__(self, host: str = "localhost", port: int = 15672, 
                 admin_user: str = "guest", admin_password: str = "guest"):
        self.base_url = f"http://{host}:{port}/api"
        self.auth = HTTPBasicAuth(admin_user, admin_password)
        self.session = requests.Session()
        self.session.auth = self.auth
        
    def _make_request(self, method: str, endpoint: str, data: Optional[Dict] = None) -> requests.Response:
        url = f"{self.base_url}/{endpoint}"
        headers = {"Content-Type": "application/json"}
        
        try:
            if method == "GET":
                response = self.session.get(url, headers=headers)
            elif method == "PUT":
                response = self.session.put(url, headers=headers, json=data)
            elif method == "POST":
                response = self.session.post(url, headers=headers, json=data)
            elif method == "DELETE":
                response = self.session.delete(url, headers=headers)
            else:
                raise ValueError(f"Unsupported HTTP method: {method}")
            
            return response
        except requests.exceptions.RequestException as e:
            print(f"Error making request to {url}: {e}")
            raise
    
    def check_connection(self) -> bool:
        try:
            response = self._make_request("GET", "overview")
            if response.status_code == 200:
                print("Successfully connected to RabbitMQ Management API")
                return True
            else:
                print(f"Failed to connect: {response.status_code}")
                return False
        except Exception as e:
            print(f"Connection error: {e}")
            return False
    
    def create_vhost(self, vhost_config: VHostConfig) -> bool:
        print(f"Creating virtual host: {vhost_config.name}")
        
        data = {
            "tracing": vhost_config.tracing
        }
        
        if vhost_config.description:
            data["description"] = vhost_config.description
        
        response = self._make_request("PUT", f"vhosts/{vhost_config.name}", data)
        
        if response.status_code in [201, 204]:
            print(f"Virtual host '{vhost_config.name}' created successfully")
            return True
        else:
            print(f"Failed to create vhost '{vhost_config.name}': {response.status_code} - {response.text}")
            return False
    
    def delete_vhost(self, vhost_name: str) -> bool:
        print(f"Deleting virtual host: {vhost_name}")
        
        response = self._make_request("DELETE", f"vhosts/{vhost_name}")
        
        if response.status_code == 204:
            print(f"Virtual host '{vhost_name}' deleted successfully")
            return True
        else:
            print(f"Failed to delete vhost '{vhost_name}': {response.status_code}")
            return False
    
    def list_vhosts(self) -> List[Dict]:
        response = self._make_request("GET", "vhosts")
        
        if response.status_code == 200:
            vhosts = response.json()
            print(f"\nFound {len(vhosts)} virtual hosts:")
            for vhost in vhosts:
                print(f"  - {vhost['name']}")
            return vhosts
        else:
            print(f"Failed to list vhosts: {response.status_code}")
            return []
    
    def create_user(self, user_config: UserConfig) -> bool:
        print(f"Creating user: {user_config.username}")
        
        data = {
            "password": user_config.password,
            "tags": user_config.tags
        }
        
        response = self._make_request("PUT", f"users/{user_config.username}", data)
        
        if response.status_code in [201, 204]:
            print(f"User '{user_config.username}' created successfully")
            return True
        else:
            print(f"Failed to create user '{user_config.username}': {response.status_code} - {response.text}")
            return False
    
    def delete_user(self, username: str) -> bool:
        print(f"Deleting user: {username}")
        
        response = self._make_request("DELETE", f"users/{username}")
        
        if response.status_code == 204:
            print(f"User '{username}' deleted successfully")
            return True
        else:
            print(f"Failed to delete user '{username}': {response.status_code}")
            return False
    
    def list_users(self) -> List[Dict]:
        response = self._make_request("GET", "users")
        
        if response.status_code == 200:
            users = response.json()
            print(f"\nFound {len(users)} users:")
            for user in users:
                print(f"  - {user['name']} (tags: {user.get('tags', 'none')})")
            return users
        else:
            print(f"Failed to list users: {response.status_code}")
            return []
    
    def set_permissions(self, permission_config: PermissionConfig) -> bool:
        print(f"Setting permissions for user '{permission_config.username}' on vhost '{permission_config.vhost}'")
        
        data = {
            "configure": permission_config.configure,
            "write": permission_config.write,
            "read": permission_config.read
        }
        
        response = self._make_request(
            "PUT", 
            f"permissions/{permission_config.vhost}/{permission_config.username}", 
            data
        )
        
        if response.status_code in [201, 204]:
            print(f"Permissions set successfully")
            return True
        else:
            print(f"Failed to set permissions: {response.status_code} - {response.text}")
            return False
    
    def delete_permissions(self, vhost: str, username: str) -> bool:
        print(f"Deleting permissions for user '{username}' on vhost '{vhost}'")
        
        response = self._make_request("DELETE", f"permissions/{vhost}/{username}")
        
        if response.status_code == 204:
            print(f"Permissions deleted successfully")
            return True
        else:
            print(f"Failed to delete permissions: {response.status_code}")
            return False
    
    def list_permissions(self, vhost: Optional[str] = None, username: Optional[str] = None) -> List[Dict]:
        if username:
            endpoint = f"users/{username}/permissions"
        elif vhost:
            endpoint = f"vhosts/{vhost}/permissions"
        else:
            endpoint = "permissions"
        
        response = self._make_request("GET", endpoint)
        
        if response.status_code == 200:
            permissions = response.json()
            print(f"\nFound {len(permissions)} permission entries:")
            for perm in permissions:
                print(f"  - User: {perm['user']}, VHost: {perm['vhost']}")
                print(f"    Configure: {perm['configure']}, Write: {perm['write']}, Read: {perm['read']}")
            return permissions
        else:
            print(f"Failed to list permissions: {response.status_code}")
            return []
    
    def set_topic_permissions(self, vhost: str, username: str, exchange: str, 
                             write: str = ".*", read: str = ".*") -> bool:
        print(f"Setting topic permissions for user '{username}' on vhost '{vhost}'")
        
        data = {
            "exchange": exchange,
            "write": write,
            "read": read
        }
        
        response = self._make_request(
            "PUT", 
            f"topic-permissions/{vhost}/{username}", 
            data
        )
        
        if response.status_code in [201, 204]:
            print(f"Topic permissions set successfully")
            return True
        else:
            print(f"Failed to set topic permissions: {response.status_code} - {response.text}")
            return False
    
    def get_vhost_info(self, vhost_name: str) -> Optional[Dict]:
        response = self._make_request("GET", f"vhosts/{vhost_name}")
        
        if response.status_code == 200:
            return response.json()
        else:
            print(f"Failed to get vhost info: {response.status_code}")
            return None
    
    def get_user_info(self, username: str) -> Optional[Dict]:
        response = self._make_request("GET", f"users/{username}")
        
        if response.status_code == 200:
            return response.json()
        else:
            print(f"Failed to get user info: {response.status_code}")
            return None


def setup_multi_tenant_environment(manager: RabbitMQManager):
    print("\n" + "="*60)
    print("Setting up Multi-Tenant RabbitMQ Environment")
    print("="*60 + "\n")
    
    tenants = [
        {
            "name": "tenant_app1",
            "description": "Application 1 Virtual Host",
            "users": [
                {"username": "app1_producer", "password": "producer_pass123", "tags": ""},
                {"username": "app1_consumer", "password": "consumer_pass123", "tags": ""}
            ],
            "permissions": [
                {
                    "username": "app1_producer",
                    "configure": "^app1-.*",
                    "write": "^app1-.*",
                    "read": "^$"
                },
                {
                    "username": "app1_consumer",
                    "configure": "^$",
                    "write": "^$",
                    "read": "^app1-.*"
                }
            ]
        },
        {
            "name": "tenant_app2",
            "description": "Application 2 Virtual Host",
            "users": [
                {"username": "app2_service", "password": "service_pass456", "tags": ""},
            ],
            "permissions": [
                {
                    "username": "app2_service",
                    "configure": ".*",
                    "write": ".*",
                    "read": ".*"
                }
            ]
        },
        {
            "name": "tenant_analytics",
            "description": "Analytics Service Virtual Host",
            "users": [
                {"username": "analytics_worker", "password": "analytics_pass789", "tags": ""},
            ],
            "permissions": [
                {
                    "username": "analytics_worker",
                    "configure": "^analytics-.*",
                    "write": "^analytics-.*",
                    "read": "^analytics-.*"
                }
            ]
        }
    ]
    
    for tenant in tenants:
        print(f"\n--- Configuring Tenant: {tenant['name']} ---")
        
        vhost_config = VHostConfig(
            name=tenant["name"],
            description=tenant["description"]
        )
        manager.create_vhost(vhost_config)
        
        for user_data in tenant["users"]:
            user_config = UserConfig(
                username=user_data["username"],
                password=user_data["password"],
                tags=user_data["tags"]
            )
            manager.create_user(user_config)
        
        for perm_data in tenant["permissions"]:
            perm_config = PermissionConfig(
                vhost=tenant["name"],
                username=perm_data["username"],
                configure=perm_data["configure"],
                write=perm_data["write"],
                read=perm_data["read"]
            )
            manager.set_permissions(perm_config)
    
    print("\n" + "="*60)
    print("Multi-Tenant Environment Setup Complete")
    print("="*60 + "\n")


def main():
    rabbitmq_host = "localhost"
    rabbitmq_port = 15672
    admin_user = "guest"
    admin_password = "guest"
    
    manager = RabbitMQManager(
        host=rabbitmq_host,
        port=rabbitmq_port,
        admin_user=admin_user,
        admin_password=admin_password
    )
    
    if not manager.check_connection():
        print("Failed to connect to RabbitMQ. Exiting.")
        sys.exit(1)
    
    setup_multi_tenant_environment(manager)
    
    print("\n--- Current Virtual Hosts ---")
    manager.list_vhosts()
    
    print("\n--- Current Users ---")
    manager.list_users()
    
    print("\n--- All Permissions ---")
